## 5. API请求封装（迭代1）

### 5.1 认证API

```typescript
// src/api/auth.ts
import { request } from '../utils/request';
import { ApiResponse, User } from '../types/api';

// 微信扫码登录
export interface WechatLoginRequest {
  code: string;
}

export interface WechatLoginResponse {
  token: string;
  user: User;
}

export const wechatLogin = (code: string) => {
  return request.post<ApiResponse<WechatLoginResponse>>(
    '/api/v1/auth/wechat-qrcode',
    { code }
  );
};

// 获取当前用户信息
export const getMe = () => {
  return request.get<ApiResponse<User>>('/api/v1/me');
};

// 退出登录
export const logout = () => {
  return request.post<ApiResponse<void>>('/api/v1/auth/exit');
};

// 手机号验证码登录 (P1)
export interface PhoneLoginRequest {
  phone: string;
  code: string;
}

export const phoneLogin = (data: PhoneLoginRequest) => {
  return request.post<ApiResponse<WechatLoginResponse>>(
    '/api/v1/auth/phone-login',
    data
  );
};
```

### 5.2 方法论配置API

```typescript
// src/api/method.ts
import { request } from '../utils/request';
import { ApiResponse, PaginationResponse, MethodConfig } from '../types/api';

// 获取方法论列表
export interface GetMethodListParams {
  page?: number;
  page_size?: number;
  is_active?: number;
}

export const getMethodList = (params: GetMethodListParams) => {
  return request.get<ApiResponse<PaginationResponse<MethodConfig>>>(
    '/api/v1/methods',
    { params }
  );
};

// 新增方法论
export interface CreateMethodRequest {
  method_id: string;
  name: string;
  description: string;
  prompt_template: string;
  output_template?: string;
  is_active: number;
  sort_order: number;
}

export const createMethod = (data: CreateMethodRequest) => {
  return request.post<ApiResponse<MethodConfig>>('/api/v1/methods', data);
};

// 编辑方法论
export const updateMethod = (id: number, data: CreateMethodRequest) => {
  return request.put<ApiResponse<MethodConfig>>(`/api/v1/methods/${id}`, data);
};

// 切换启用/禁用
export const toggleMethod = (id: number) => {
  return request.patch<ApiResponse<{is_active: number}>>(
    `/api/v1/methods/${id}/toggle`
  );
};

// 测试方法论
export interface TestMethodRequest {
  user_input: string;
}

export const testMethod = (id: number, data: TestMethodRequest) => {
  return request.post<ApiResponse<string>>(
    `/api/v1/methods/${id}/test`,
    data
  );
};
```

